    private void crearGrupo(UsuarioRepository ur, LocalGastronomicoRepository lr, ProductoServicioRepository pr, PasswordEncoder pe, String[][] datos) {
        for(String[] localData : datos) {
            String email = localData[1];
            Optional<Usuario> opt = ur.findByEmail(email);
            Usuario user = opt.orElse(new Usuario());
            if(opt.isEmpty()) {
                user.setNombre(localData[0]); user.setApellido("Local"); user.setEmail(email); user.setPassword(pe.encode("123456")); user.setRol(Rol.ALIADO_GASTRONOMICO); user.setEstado(true); user.setTelefono("12345678");
                user = ur.save(user);
                LocalGastronomico local = new LocalGastronomico(); local.setAliado(user); local.setNombre(localData[0]); local.setTipoLocal(localData[2]); local.setDireccion(localData[3]); local.setTelefono("12345678"); local.setHorarios("10:00 - 22:00"); local.setPortadaUrl(localData[4]); local.setDescripcion("Lo mejor de " + localData[0]);
                lr.save(local);
                for(int i=6; i<localData.length; i++) {
                    String[] parts = localData[i].split("-");
                    String nombre = parts[0]; String precio = parts[1]; String img = parts[2]; CategoriaProducto cat = CategoriaProducto.PLATO;
                    if(localData[5].equals("CafeterÃ­a")) cat = CategoriaProducto.CAFE;
                    else if(localData[5].equals("ReposterÃ­a")) cat = CategoriaProducto.TORTA;
                    else if(localData[5].equals("HeladerÃ­a")) cat = CategoriaProducto.TORTA;
                    else if(localData[5].equals("Comida rÃ¡pida")) cat = CategoriaProducto.COMBO;
                    crearProducto(pr, user, nombre, precio, cat, img);
                }
            }
        }
    }
    private void crearProducto(ProductoServicioRepository repo, Usuario usuario, String titulo, String precio, CategoriaProducto cat, String imageUrl) {
        ProductoServicio p = new ProductoServicio();
        p.setUsuarioOfertante(usuario); p.setTitulo(titulo); p.setDescripcion(titulo + " especial"); p.setPrecio(new BigDecimal(precio)); p.setCategoria(cat); p.setEstadoValidacion(EstadoValidacion.APROBADO); p.setImagenUrl(imageUrl);
        repo.save(p);
    }
